enum Direction {
  Up = "UP",
  Down = "DOWN",
  Left = "LEFT",
  Right = "RIGHT"
}

// Usage of Enum
function moveEnum(direction: Direction) {
  console.log(`Moving: ${direction}`);
}

moveEnum(Direction.Up); // Output: Moving: UP

// Using Union Types
type DirectionUnion = "UP" | "DOWN" | "LEFT" | "RIGHT";

function moveUnion(direction: DirectionUnion) {
  console.log(`Moving: ${direction}`);
}

moveUnion("LEFT"); // Output: Moving: LEFT

interface User {
  name: string;
  age: number;
}

const user: User = {
  name: 'Alice',
  age: 30
};

console.log(user.email); // Error: Property 'email' does not exist on type 'User'.

interface User {
  name: string;
  age: number;
  email?: string; // optional property
}

const user: User = {
  name: 'Alice',
  age: 30
};

// Now this is valid because email is optional
console.log(user.email);

// Or using type assertion
console.log((user as any).email);

